problems.solutionCode:
public class Q1 {
    public static void main(String[] args) {
        System.out.println("Table: EMPLOYEE(emp_id, emp_name, dept_id, dept_name,");
        System.out.println("       dept_location, project_id, project_name, hours_worked)");
        System.out.println("PK: (emp_id, project_id)");
        System.out.println();
        System.out.println("1NF: SATISFIED");
        System.out.println("  - All values appear atomic");
        System.out.println("  - Has a composite primary key");
        System.out.println("  - No repeating groups");
        System.out.println();
        System.out.println("2NF VIOLATIONS (partial dependencies on composite PK):");
        System.out.println("  emp_id → emp_name, dept_id, dept_name, dept_location");
        System.out.println("    (these depend only on emp_id, not the full PK)");
        System.out.println("  project_id → project_name");
        System.out.println("    (depends only on project_id, not the full PK)");
        System.out.println("  Only hours_worked depends on BOTH emp_id AND project_id → OK");
        System.out.println();
        System.out.println("3NF VIOLATIONS (transitive dependencies):");
        System.out.println("  emp_id → dept_id → dept_name, dept_location");
        System.out.println("  dept_id is a non-key; dept_name/location depend on dept_id");
        System.out.println("  => transitive dependency through a non-key attribute");
        System.out.println();
        System.out.println("Normalized 3NF Schema:");
        System.out.println();
        System.out.println("  DEPARTMENTS(dept_id PK, dept_name, dept_location)");
        System.out.println("    Fixes: dept_name/dept_location depend only on dept_id");
        System.out.println();
        System.out.println("  EMPLOYEES(emp_id PK, emp_name, dept_id FK→DEPARTMENTS)");
        System.out.println("    Fixes: emp_name depends on emp_id only");
        System.out.println("           dept_id is FK, not name (removes transitive dep)");
        System.out.println();
        System.out.println("  PROJECTS(project_id PK, project_name)");
        System.out.println("    Fixes: project_name depends on project_id only");
        System.out.println();
        System.out.println("  ASSIGNMENTS(emp_id FK, project_id FK, hours_worked)");
        System.out.println("    PK: (emp_id, project_id)");
        System.out.println("    hours_worked is the only column depending on full PK");
        System.out.println();
        System.out.println("Summary: 1 table → 4 tables. Each fact stored once.");
    }
}
